 (332,'AT4 84mm Disposable Rocket Launcher','at4-84mm-disposable-rocket-launcher',5,39,69,'84mm unguided disposable anti-armor rocket launcher. 300m effective range, 420mm RHA penetration, shoulder-fired, single shot. NATO standard disposable launcher — every modern military FPS from Call of Duty to Battlefield includes it.',34990.0,0.0,20,4.9,234,'at4_84mm_disposable_rocket_launcher.png','["at4","anti-armor","disposable","84mm","nato","iconic","gaming","launcher","call-of-duty"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (333,'PASGT Ballistic Helmet NIJ IIIA','pasgt-ballistic-helmet-nij-iiia',13,85,28,'NIJ Level IIIA PASGT-pattern ballistic helmet. Kevlar composite, 1.4kg, 4-point retention harness. US military standard 1983 through early 2000s. The most iconic modern military helmet — in every military game from the 1990s onward.',24990.0,0.0,35,4.7,312,'pasgt_ballistic_helmet_nij_iiia.png','["helmet","pasgt","level-iiia","kevlar","military","iconic","gaming","us-army"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (334,'M1 Steel Pot Helmet WWII','m1-steel-pot-helmet-wwii',13,85,69,'Steel M1 helmet with OD cotton liner and chinstrap. 2.85 lb manganese steel shell. Standard US WWII through Vietnam era — the "Steel Pot." The definitive American military helmet in every WWII and Vietnam game and film.',4990.0,0.0,50,4.8,543,'m1_steel_pot_helmet_wwii.png','["helmet","m1","wwii","vietnam","steel-pot","iconic","steel","us-army","gaming","film"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (335,'M1935 Stahlhelm German WWII Helmet','m1935-stahlhelm-german-wwii',13,85,69,'German WWII M1935 Stahlhelm. Steel construction, leather liner, single-comb Y-strap chinstrap. The instantly recognizable German helmet of both World Wars — in every WWII game ever made.',5990.0,0.0,35,4.7,312,'m1935_stahlhelm_german_wwii.png','["stahlhelm","german","wwii","wwi","steel","iconic","helmet","gaming","m35"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (336,'Interceptor OTV Body Armor NIJ IIIA','interceptor-otv-body-armor-nij-iiia',13,86,28,'Outer Tactical Vest NIJ Level IIIA with SAPI plate pockets, MOLLE II webbing, throat/groin/deltoid protection. US military standard 2000s–2010s. Iconic in Call of Duty Modern Warfare and every 2000s US-military game.',44990.0,0.0,15,4.7,145,'interceptor_otv_body_armor_nij_iiia.png','["interceptor","otv","iiia","molle","sapi","military","iconic","modern-warfare","gaming"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (337,'Medieval Chainmail Hauberk Norse','medieval-chainmail-hauberk-norse',13,88,69,'Butted mild steel chainmail hauberk. Knee-length, long sleeves, coif hood, 8mm rings, riveted at stress points. Norse/early medieval pattern — standard protection from the Dark Ages through 13th century. Featured in God of War and Assassin''s Creed.',19990.0,0.0,10,4.7,45,'medieval_chainmail_hauberk_norse.png','["chainmail","hauberk","viking","norse","medieval","iconic","god-of-war","assassins-creed"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (338,'Full Plate Armor Gauntlets 16g Steel','full-plate-armor-gauntlets-16g',13,86,69,'Articulated 16-gauge steel plate gauntlets. Full finger articulation, knuckle plates, leather liner. Replica of 15th-century tournament and battlefield armor. Featured in Dark Souls, Mordhau, and every full-armor medieval game.',9990.0,0.0,20,4.6,67,'full_plate_armor_gauntlets_16g.png','["gauntlets","plate-armor","medieval","articulated","knight","iconic","dark-souls","mordhau"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (339,'AN/PVS-14 Gen III+ Night Vision Monocular','an-pvs14-gen3-night-vision-monocular',15,103,69,'Gen III+ night vision monocular. 40° FOV, 1x magnification, head-mount or weapon-rail compatible, 12-hour battery. NATO standard NVD — the definitive special operations night vision device. Iconic in ghost-ops and tactical gaming.',149990.0,0.0,10,4.9,123,'an_pvs14_gen3_night_vision_monocular.png','["pvs14","night-vision","gen3","monocular","nato","iconic","gaming","sof","tactical"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (340,'Trijicon ACOG 4x32 BDC Combat Optic','trijicon-acog-4x32-bdc-optic',15,103,32,'Trijicon 4x32 ACOG with 5.56mm BDC reticle, fiber optic/tritium illumination, TA51 flat-top mount. The most iconic combat optic in the world — US military standard and in every military FPS from Call of Duty 4 onward.',44990.0,0.0,20,4.9,534,'trijicon_acog_4x32_bdc_optic.png','["acog","4x32","trijicon","m16","ar-15","combat-optic","iconic","gaming","call-of-duty-4"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (341,'ALICE Pack Large LC-2 External Frame','alice-pack-large-lc2-external-frame',14,96,30,'All-purpose Lightweight Individual Carrying Equipment large rucksack. 2,650 cubic inches, external frame, OD green nylon. US military standard Vietnam through Gulf War. Iconic in every Vietnam and Cold War era game.',9990.0,0.0,45,4.6,234,'alice_pack_large_lc2_external_frame.png','["alice","lc2","rucksack","military","vietnam","gulf-war","iconic","external-frame","oda"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (342,'M1943 Folding Entrenching Tool','m1943-folding-entrenching-tool',19,136,69,'Folding tri-fold entrenching tool. Alloy steel blade, hardwood handle, OD nylon carrier. US standard WWII through Gulf War. The iconic "e-tool" — dig, pry, improvised weapon. Every military survival game includes one.',2990.0,0.0,80,4.5,312,'m1943_folding_entrenching_tool.png','["e-tool","entrenching","wwii","vietnam","military","iconic","folding","survival","gaming"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (343,'USGI 1qt Canteen with M1910 Cover','usgi-1qt-canteen-m1910-cover',19,133,69,'1-quart USGI aluminum canteen with M1910 OD cotton canvas cover and M1910 steel cup. Standard US military canteen from WWI through Vietnam. Iconic in every war game and essential militaria collectible.',1990.0,0.0,100,4.6,456,'usgi_1qt_canteen_m1910_cover.png','["canteen","usgi","m1910","wwii","vietnam","military","iconic","1qt","survival","collectible"]',0,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
