 (129,'AK-47/AKM Underfolder Paratrooper Conversion','custom-ak-underfolder-paratrooper',22,152,142,'Convert any AK-pattern rifle to Soviet underfolder paratrooper configuration. Hardware swap, timing, headspace check, and 50-round function test. Classic Cold War paratrooper look.',14990.0,0.0,4.8,78,'ak_underfolder_paratrooper_conversion.png','["ak","underfolder","paratrooper","conversion","soviet","custom","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (130,'Desert Eagle Full Cerakote — Titanium Silver','custom-deagle-cerakote-titanium-silver',22,154,148,'Complete Desert Eagle Cerakote refinish in Titanium Silver. Full disassembly, bead-blast prep, two-coat application, 250°F oven cure, reassembly, and function fire.',9990.0,10.0,4.7,56,'desert_eagle_cerakote_titanium_silver.png','["desert-eagle","cerakote","titanium","finish","custom","iconic","imi"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (131,'M1911 Full Combat Package Upgrade','custom-m1911-full-combat-package',22,156,54,'Full combat 1911 transformation: 3.5 lb trigger job, match barrel, flared magwell, beavertail grip safety, front/rear serrations, carry bevel, and test fire. Bring this icon to modern performance standards.',29990.0,0.0,4.9,102,'m1911_full_combat_package_upgrade.png','["1911","trigger","match-barrel","magwell","beavertail","combat","custom","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (132,'Kar98k Full Cosmetic Restoration & Re-Bluing','custom-kar98k-full-restoration-rebluing',22,157,69,'Full WWII Kar98k surplus restoration. Metal polish, rust removal, slow-rust cold re-blue, stock strip and Danish oil refinish, headspace check, bore clean. Returns rifle to matching-number display or shooter condition.',19990.0,0.0,4.9,45,'kar98k_full_restoration_rebluing.png','["kar98k","restoration","re-bluing","wwii","surplus","matching-numbers","custom"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (133,'AK Walnut Classic Furniture Set Install','custom-ak-walnut-furniture-install',22,152,142,'Replace synthetic AK furniture with hand-fitted matched walnut stock, handguard, and pistol grip. Fitting, finish sanding, oil treatment, and reinstall included. Restores the original WWII-era AK-47 look.',9990.0,5.0,4.8,67,'ak_walnut_furniture_set_install.png','["ak","walnut","furniture","wood","classic","custom","upgrade","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (134,'Medieval Longsword Full Sharpening & Balance Job','custom-longsword-sharpen-balance',22,157,8,'Professional sharpening, edge geometry re-profiling, and dynamic balance-point adjustment for longswords and arming swords. Brought to functional fighting edge and correct point-of-balance.',4990.0,0.0,4.8,89,'longsword_full_sharpening_balance.png','["longsword","sharpening","balancing","medieval","sword","custom","edge","hema"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (135,'M1 Garand Full Rebuild & Match Tuning','custom-m1-garand-full-rebuild-match',22,156,146,'Complete M1 Garand rebuild: headspace check, new operating rod spring, gas plug service, throat erosion gauge, trigger job to 4.5 lb, stock refinish. Returns this WWII legend to match-grade function.',24990.0,0.0,4.9,34,'m1_garand_full_rebuild_match_tuning.png','["m1-garand","rebuild","match","headspace","trigger","wwii","iconic","springfield"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (136,'Thompson SMG Depot-Level Overhaul','maint-thompson-smg-depot-overhaul',23,161,55,'Complete depot-level disassembly, inspection, and rebuild of M1/M1A1 Thompson SMGs. Parts inspection and replacement, timing, headspace, cyclic rate check, and 50-round test fire.',24990.0,0.0,4.8,34,'thompson_smg_depot_overhaul.png','["thompson","m1a1","smg","overhaul","depot","wwii","maintenance","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (137,'WWII Bolt-Action Rifle Full Service (Kar98k / Lee-Enfield / Mosin)','maint-wwii-bolt-action-full-service',23,162,55,'Complete service for WWII bolt-action rifles. Headspace check, extractor inspection, firing pin replacement if needed, bore cleaning, action lube, and wood stock conditioning. Covers Kar98k, Lee-Enfield, Mosin-Nagant.',12990.0,0.0,4.9,56,'wwii_bolt_action_full_service.png','["bolt-action","wwii","kar98k","lee-enfield","mosin","service","maintenance","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (138,'Lever-Action Rifle Action Smoothing & Trigger Job','maint-lever-action-action-trigger-job',23,162,69,'Precision action smoothing and trigger job for Winchester 1894, Marlin 336, and similar lever-action rifles. Sear honing, carrier polish, bolt geometry, timing, and live-fire verification.',7990.0,0.0,4.7,67,'lever_action_action_trigger_job.png','["lever-action","trigger","action","winchester","marlin","smoothing","maintenance"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (139,'AK-Pattern Rifle Full Deep Clean & Inspect','maint-ak-pattern-full-deep-clean',23,158,55,'Complete AK-pattern rifle deep cleaning and inspection. Ultrasonic receiver clean, barrel scrub, gas tube service, bolt/carrier inspection, all springs checked, lubricated and function tested.',6990.0,0.0,4.8,89,'ak_pattern_full_deep_clean_inspect.png','["ak","ak-47","akm","clean","inspect","maintenance","kalashnikov","service"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (140,'WWII Infantry Weapons Familiarization — Full Day','train-wwii-infantry-weapons-full-day',26,177,59,'Full-day hands-on WWII weapons familiarization. M1 Garand, Thompson M1A1, MP40, Kar98k, Bren Gun, M1911A1, and Mk 2 grenade (inert). Safe handling, historical context, disassembly, and supervised live fire. All ammo included.',19990.0,0.0,4.9,89,'wwii_infantry_weapons_familiarization.png','["wwii","m1-garand","thompson","mp40","kar98k","bren","1911","live-fire","historical","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (141,'AK Platform Operator Course — 1 Day','train-ak-platform-operator-1day',26,177,59,'1-day AK-pattern rifle operator course. Fundamentals, malfunction clearing, magazine changes, accuracy and speed drills, 300-round shoot. Covers AK-47, AKM, and common variants. Most iconic rifle platform course offered.',14990.0,0.0,4.9,112,'ak_platform_operator_course.png','["ak-47","akm","operator","course","live-fire","kalashnikov","iconic","training","300-round"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (142,'M1911 Pistol Combat Shooting — 2 Day','train-m1911-combat-shooting-2day',26,178,59,'2-day M1911-focused pistol combat course. Draw, press, malfunction clearing, retention shooting, magazine manipulation, and 500-round proficiency shoot. Historical lineage of this 100-year-old icon covered.',24990.0,0.0,4.8,78,'m1911_pistol_combat_shooting_2day.png','["1911","pistol","combat","shooting","2-day","iconic","m1911","training"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (143,'Revolver Mastery — .44 Magnum Full Day','train-revolver-mastery-44mag-full-day',26,178,59,'Full-day double-action revolver mastery using the S&W Model 29 .44 Magnum. Fundamentals, trigger control, speed-loading with HKS speedloaders, low-light drills, and 200-round qualification shoot.',14990.0,0.0,4.8,67,'revolver_mastery_44mag_full_day.png','["revolver","44-magnum","sw-model-29","marksmanship","speed-loader","iconic","training"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (144,'Historical European Martial Arts — Longsword (HEMA)','train-hema-longsword-fundamentals',26,177,69,'1-day HEMA longsword fundamentals course. Guards, basic cuts and thrusts from Liechtenauer''s system, half-swording, and partner drilling. Loaner synthetic longswords provided. Perfect for medieval gaming enthusiasts.',7990.0,0.0,4.8,45,'hema_longsword_fundamentals.png','["hema","longsword","medieval","swordsmanship","historical","iconic","liechtenauer","training"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (145,'Soviet WWII Weapons Familiarization — Eastern Front Package','train-soviet-wwii-eastern-front',26,177,59,'Half-day hands-on Soviet WWII weapons course. Mosin-Nagant M91/30, PPSh-41, TT-33 pistol, and DP-28 LMG (inert demo). Historical context, safe handling, and supervised live fire on Mosin and PPSh.',14990.0,0.0,4.8,56,'soviet_wwii_eastern_front_familiarization.png','["wwii","soviet","mosin","ppsh41","tt33","eastern-front","historical","live-fire","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (146,'Historic & Collectible Firearm Provenance Appraisal','consult-historic-firearm-provenance-appraisal',28,187,62,'Expert authentication and provenance research for historic and collectible firearms. WWII militaria, Wild West revolvers, Cold War weapons. Photographic documentation, written appraisal report, and certificate of authenticity issued.',9990.0,0.0,4.9,34,'historic_firearm_provenance_appraisal.png','["appraisal","authentication","provenance","collectible","wwii","historic","certificate","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (147,'WWII Militaria Collection Cataloguing & Valuation','consult-wwii-collection-catalogue-valuation',28,191,62,'Full cataloguing of WWII militaria and weapons collections. Photographic documentation, historical research, condition grading, current market valuation, and encrypted digital inventory report.',19990.0,0.0,4.8,18,'wwii_collection_catalogue_valuation.png','["wwii","collection","catalogue","militaria","valuation","documentation","historic","appraisal"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (148,'WWII Surplus Small Arms Demilitarization','disposal-wwii-surplus-small-arms',31,208,65,'ATF/BATFE-compliant demilitarization of surplus WWII-era small arms: M1 Garand, Thompson, Kar98k, Lee-Enfield, etc. Weld/cut per regulations, full documentation package. Museum-finish display option available.',19990.0,0.0,4.8,23,'wwii_surplus_small_arms_demil.png','["wwii","demilitarization","surplus","atf","m1-garand","thompson","kar98k","disposal","compliant"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (149,'WWII Small Arms Comparative Ballistics Study','research-wwii-small-arms-ballistics-study',29,196,63,'Comprehensive ballistic and ergonomic performance study of WWII small arms: M1 Garand, Kar98k, Mosin, Lee-Enfield, MP40, PPSh-41. Gelatin testing, accuracy benchmarking, comparative analytical report.',499990.0,0.0,4.9,6,'wwii_small_arms_ballistics_study.png','["wwii","small-arms","ballistics","historical","research","comparative","iconic","m1-garand","kar98k"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27'),
 (150,'Battlefield HUMINT Intelligence Package','surv-battlefield-humint-package',32,213,62,'Human intelligence collection package for conflict zones. Trained field operatives, structured HUMINT reporting in SALUTE and BLUF format, operational security protocol, and secure comms.',999990.0,0.0,4.9,7,'battlefield_humint_intelligence_package.png','["humint","intelligence","field","conflict","salute","operational-security","surveillance","iconic"]',1,'2026-04-25 12:10:27','2026-04-25 12:10:27');
